/* ============================================================================
   ΠΕΡΙΓΡΑΦΕΣ ΠΡΟΣΦΟΡΩΝ — συνεργαζόμενο αρχείο του «Αντλίες CRM»
   ----------------------------------------------------------------------------
   Το κύριο πρόγραμμα μαζεύει τα στοιχεία της προσφοράς και καλεί
   PERIGRAFES.start(ctx). Εδώ ζουν:
     • Η βιβλιοθήκη σειρών (MODELS): κείμενα + φωτογραφίες ανά σειρά αντλίας
     • Το λεξικό υλικών: ΜΟΝΟ τα βασικά υλικά εμφανίζονται (λίστα WHITELIST)
     • Τα τρία κουτιά κτιρίου (ταυτότητα / δεδομένα απωλειών / δομικά στοιχεία)
       — γεμίζουν από τον Υπολογιστή Θερμικών Απωλειών (ctx.hl)
     • Το παράθυρο επιλογών πριν τη δημιουργία (θέση, διανομή, αποξηλώσεις)
     • Η σύνταξη του εγγράφου Word (docx.js) κατά το πρότυπο της εταιρείας
   Για νέα σειρά αντλίας: προσθέτουμε εγγραφή στο MODELS — το CRM δεν αλλάζει.
   ============================================================================ */
window.PERIGRAFES=(function(){
  'use strict';

  // ---------- Φωτογραφίες (ενσωματωμένες, base64 JPEG) ----------
  var IMG_ATL_EXT='';   // εξωτερική μονάδα
  var IMG_ATL_INT='';   // εσωτερική υδραυλική μονάδα
  var IMG_ATL_AMB='';   // εγκατεστημένη σε χώρο

  function b64u8(s){var bin=atob(s),u=new Uint8Array(bin.length);for(var i=0;i<bin.length;i++)u[i]=bin.charCodeAt(i);return u;}
  function fmtE(n){return (n||0).toLocaleString('el-GR',{minimumFractionDigits:2,maximumFractionDigits:2})+' €';}
  function litersFrom(name){var m=String(name||'').match(/(\d+(?:\s*[-–]\s*\d+)?)\s*lit/i);return m?m[1].replace(/\s/g,''):null;}

  // ---------- Βιβλιοθήκη σειρών αντλιών ----------
  var MODELS=[
    {
      key:'atlantic_extensa',
      seriesLabel:'Atlantic Alfea Extensa',
      match:function(ctx){return ctx.equipType!=='gas'&&ctx.brandId==='atlantic'&&String(ctx.pumpName).indexOf('Extensa')>=0;},
      tech:function(ctx){
        return 'Η αντλία θερμότητας αέρα – νερού Atlantic '+ctx.pumpName+' της γαλλικής εταιρίας Atlantic είναι αντλία θερμότητας τύπου monoblock της σειράς Alfea Extensa, με τεχνολογία inverter και οικολογικό ψυκτικό μέσο R32. Ανήκει σε υψηλή ενεργειακή κλάση «Α++ έως Α+++»'+(ctx.pumpKw?' και αποδίδει ονομαστική θερμική ισχύ περίπου '+ctx.pumpKw:'')+'. Είναι κατάλληλη για αξιόπιστη λειτουργία σε πολύ χαμηλές εξωτερικές θερμοκρασίες και μπορεί να θερμάνει το νερό έως τους 60 °C, ενώ σε λειτουργία θέρμανσης συστημάτων χαμηλών θερμοκρασιών (ενδοδαπέδια ή fan coils) αποδίδει με πολύ υψηλό βαθμό απόδοσης. Οι κινητήρες της μονάδας είναι συνεχούς ρεύματος (ALL DC). Το σύστημα αποτελείται από την εξωτερική monoblock αντλία θερμότητας, την εσωτερική υδραυλική μονάδα και το κεντρικό σύστημα ελέγχου.';
      },
      techCaption:'Η Alfea Extensa δένει αρμονικά με κάθε χώρο — διακριτική και αθόρυβη.',
      controller:'Το χειριστήριο – αισθητήριο χώρου Navilink είναι σχεδιασμένο για χρήση με τις αντλίες θερμότητας Atlantic Alfea και παρέχει πλήρη έλεγχο των βασικών λειτουργιών του συστήματος θέρμανσης και ψύξης. Διαθέτει ευανάγνωστη οθόνη και μενού για τη ρύθμιση της επιθυμητής θερμοκρασίας χώρου, τον προγραμματισμό ωραρίων λειτουργίας και την επιλογή τρόπων λειτουργίας. Υποστηρίζει σύνδεση Wi-Fi και απομακρυσμένο έλεγχο μέσω της εφαρμογής Cozytouch, επιτρέποντας παρακολούθηση και ρυθμίσεις από κινητό ή tablet.',
      advantages:function(ctx){
        return [
          'Η αντλία θερμότητας Atlantic '+ctx.pumpName+' αποτελεί μια ενεργειακά αποδοτική και «πράσινη» λύση, καθώς αξιοποιεί την ενέργεια του εξωτερικού αέρα για την κάλυψη των θερμικών αναγκών της κατοικίας με πολύ χαμηλή κατανάλωση ηλεκτρικής ενέργειας.',
          'Η αξία της ενέργειας σε όλες τις μορφές της (ρεύμα, πετρέλαιο, ξύλο κ.λπ.) αυξάνεται διαχρονικά. Η οικονομικότερη λοιπόν ενέργεια δεν είναι η ενέργεια που σήμερα είναι φθηνότερη από τις υπόλοιπες, αλλά η ενέργεια που δεν καταναλώθηκε.',
          'Η αντλία θερμότητας της σειράς Alfea Extensa είναι σύστημα που καταναλώνει έως και 75% λιγότερη ενέργεια για το ίδιο αποτέλεσμα — διαχρονικά το οικονομικότερο σύστημα θέρμανσης. Παράλληλα αναβαθμίζει την ενεργειακή κλάση του ακινήτου και είναι επιλέξιμη για προγράμματα ενεργειακής αναβάθμισης (π.χ. «Εξοικονομώ»).'
        ];
      },
      images:{ext:IMG_ATL_EXT,inner:IMG_ATL_INT,amb:IMG_ATL_AMB}
    }
  ];

  // ---------- Κείμενα δεδομένων κτιρίου (από τον υπολογιστή απωλειών) ----------
  var ZONE_GR={A:'Α',B:'Β',C:'Γ',D:'Δ'};
  var ZONE_TEXT={A:'-3 °C',B:'-8 °C',C:'-13 °C',D:'-20 °C'};
  var INS_LABEL={
    pre1979:'Κατασκευή πριν το 1979 — χωρίς θερμομόνωση',
    y1979:'Κατασκευή 1979–1989 — αρχική εφαρμογή Κανονισμού Θερμομόνωσης',
    y1990:'Κατασκευή 1990–1999 — τυπική εφαρμογή Κανονισμού Θερμομόνωσης',
    y2000:'Κατασκευή 2000–2009 — ενισχυμένη θερμομόνωση',
    kenak:'Κατασκευή 2010+ — κατά ΚΕΝΑΚ',
    nzeb:'Κτήριο σχεδόν μηδενικής κατανάλωσης (nZEB)'
  };
  var FLOOR_LABEL={ground:'Επί εδάφους',pilotis:'Επάνω από πυλωτή',closed:'Επάνω από κλειστό μη θερμαινόμενο χώρο'};
  var CEIL_LABEL={roof:'Ταράτσα / τελευταίος όροφος',attic:'Κάτω από κεραμοσκεπή',closed:'Κάτω από κλειστό μη θερμαινόμενο χώρο'};

  function buildingRows(ctx){
    var hl=ctx.hl||{};
    var box1=[],box2=[],box3=[];
    if(ctx.custName)box1.push(['Ιδιοκτήτης',ctx.custName]);
    if(ctx.custAddress)box1.push(['Διεύθυνση – περιοχή',ctx.custAddress]);
    var ergo=[ctx.propName,ctx.propHeating].filter(Boolean).join(' — ');
    if(ergo)box1.push(['Είδος έργου',ergo]);
    if(hl.area)box1.push(['Μεικτή επιφάνεια έργου',hl.area+' m²']);
    if(hl.zone){
      box2.push(['Επιθυμητή εσωτερική θερμοκρασία','22 °C']);
      box2.push(['Μέση ελάχιστη εξωτερική θερμοκρασία',(ZONE_TEXT[hl.zone]||'')+' (κλιματική ζώνη '+(ZONE_GR[hl.zone]||hl.zone)+')']);
      box2.push(['Μέγιστη επιθυμητή θερμοκρασία νερού θέρμανσης','45 °C']);
    }
    if(hl.ins){
      box3.push(['Τοιχοποιία',(INS_LABEL[hl.ins]||hl.ins)+(hl.upWall?' — έχει γίνει θερμοπρόσοψη':'')]);
      var win=hl.upWin?'Διπλοί υαλοπίνακες — αναβαθμισμένα κουφώματα':((hl.ins==='kenak'||hl.ins==='nzeb')?'Σύγχρονα κουφώματα διπλών υαλοπινάκων':'Κουφώματα περιόδου κατασκευής');
      box3.push(['Υαλοστάσια',win]);
      if(hl.floorType)box3.push(['Δάπεδα',(FLOOR_LABEL[hl.floorType]||hl.floorType)+(hl.upFloor?' — με μόνωση πυλωτής':'')]);
      if(hl.ceilType)box3.push(['Οροφή',(CEIL_LABEL[hl.ceilType]||hl.ceilType)+(hl.upCeil?' — με μόνωση οροφής':'')]);
    }
    return {box1:box1,box2:box2,box3:box3};
  }

  // ---------- Κείμενα υλικών ----------
  function distConn(dist){
    if(!dist)return 'το υφιστάμενο δίκτυο διανομής';
    if(dist.indexOf('ενδοδαπέδια')>=0)return 'τον συλλέκτη της θέρμανσης δαπέδου';
    if(dist.indexOf('σώματα')>=0)return 'το δίκτυο των θερμαντικών σωμάτων';
    if(dist.indexOf('fan')>=0)return 'το δίκτυο των fan coils';
    return 'το υφιστάμενο δίκτυο διανομής';
  }
  function distTarget(dist){
    if(!dist)return 'το δίκτυο διανομής της θέρμανσης';
    if(dist.indexOf('ενδοδαπέδια')>=0)return 'την ενδοδαπέδια θέρμανση';
    if(dist.indexOf('σώματα')>=0)return 'τα θερμαντικά σώματα';
    if(dist.indexOf('fan')>=0)return 'τα fan coils';
    return 'το δίκτυο διανομής της θέρμανσης';
  }
  // ΜΟΝΟ αυτά τα υλικά της ενότητας «Υλικά Αντλίας» εμφανίζονται στο έγγραφο
  var MAT_WHITELIST={
    av:'Αντικραδασμική βάση εξωτερικής μονάδας',
    sc:'Αναστολέας διάβρωσης StopCor A3 για την προστασία της εγκατάστασης από διάβρωση και επικαθίσεις',
    mf:'Φίλτρο Mag-Filter 1" για την προστασία του εναλλάκτη από ρινίσματα και λάσπη του δικτύου',
    ap:'Αυτόματος πληρωτής — σύστημα πλήρωσης της εγκατάστασης'
  };
  function materialsList(pumpSec,bufSec,boilSec,opts){
    var mats=[];
    if(pumpSec){
      ['av','sc','mf','ap'].forEach(function(id){
        if(pumpSec.items.some(function(i){return i.id===id;}))mats.push(MAT_WHITELIST[id]);
      });
    }
    if(bufSec&&bufSec.items.some(function(i){return i.id==='ci1'||/κυκλοφορητ|κυκλ\./i.test(i.name);}))
      mats.push('Κυκλοφορητής για '+distTarget(opts.dist));
    if(boilSec&&boilSec.items.some(function(i){return i.id==='ci2'||/κυκλοφορητ|κυκλ\./i.test(i.name);}))
      mats.push('Κυκλοφορητής φόρτισης του μπόιλερ ζεστού νερού χρήσης');
    if(boilSec&&boilSec.items.some(function(i){return i.id==='v3b'||/3οδη|τρ[ίι]οδη|ηλεκτροβ[άα]να/i.test(i.name);}))
      mats.push('Τρίοδη ηλεκτροβάνα για την εναλλαγή λειτουργίας μεταξύ θέρμανσης και ζεστού νερού χρήσης');
    mats.push('Υλικά σύνδεσης της αντλίας με '+distConn(opts.dist));
    return mats;
  }

  function bufferText(sec){
    var tank=null;
    sec.items.forEach(function(i){if(!tank&&i.id!=='ci1'&&/δοχε[ίι]ο|lit/i.test(i.name))tank=i;});
    var lit=tank?litersFrom(tank.name):null;
    var brand=(tank&&/intrasol/i.test(tank.name))?' Intrasol':'';
    return 'Στο μηχανοστάσιο θα τοποθετηθεί δοχείο αδρανείας – υδραυλικός διαχωριστής'+brand+(lit?', χωρητικότητας '+lit+' λίτρων':'')+', κατάλληλο και για λειτουργία ψύξης. Λειτουργεί ως αποθήκη νερού για την ομαλή λειτουργία του συστήματος και τον περιορισμό των εκκινήσεων της εξωτερικής μονάδας, καθώς και ως υδραυλικός διαχωριστής των καταναλώσεων της θέρμανσης.';
  }

  function boilerTypeFrom(name){
    var t=String(name||'').replace(/boiler/ig,'').replace(/μπ[όο][ιϊ]λερ/ig,'').replace(/\d+\s*(?:[-–]\s*\d+)?\s*lit\w*/ig,'').replace(/\bΑΘ\b/g,'').replace(/\s+/g,' ').trim();
    return t||null;
  }
  function boilerText(sec){
    var bo=null;
    sec.items.forEach(function(i){if(!bo&&/boiler|μπ[όο][ιϊ]λερ/i.test(i.name))bo=i;});
    var lit=bo?litersFrom(bo.name):null;
    var type=bo?boilerTypeFrom(bo.name):null;
    var brand=(bo&&/intrasol|bls/i.test(bo.name))?', της εταιρίας Intrasol':'';
    var t='Για την παραγωγή ζεστού νερού χρήσης θα τοποθετηθεί διπλής ενεργείας μπόιλερ'+brand+(type?', του τύπου '+type:'')+'.';
    t+=(lit?' Είναι χωρητικότητας '+lit+' λίτρων και ειδικά':' Είναι ειδικά')+' κατασκευασμένο για τη λειτουργία του με αντλία θερμότητας. Ο εναλλάκτης του έχει μεγάλη επιφάνεια εναλλαγής και είναι κατάλληλα τοποθετημένος για την εκμετάλλευση όλου του μπόιλερ. Είναι ελεγμένο και πιστοποιημένο για τη θέρμανση πόσιμου νερού, έχει ειδική εσωτερική επένδυση προστασίας από τη διάβρωση και ισχυρή μόνωση από σκληρή πολυουρεθάνη. Επιπλέον, για τη λειτουργία του μπόιλερ θα υπάρξει δυνατότητα να τοποθετηθεί ηλεκτρική αντίσταση, αν απαιτηθεί.';
    return t;
  }

  // ---------- Παράθυρο επιλογών πριν τη δημιουργία ----------
  function showDialog(ctx,model){
    var old=document.getElementById('pg-ovl');if(old)old.remove();
    var ovl=document.createElement('div');
    ovl.id='pg-ovl';
    ovl.style.cssText='position:fixed;inset:0;background:rgba(15,23,42,.45);z-index:9999;display:flex;align-items:center;justify-content:center';
    var selStyle='width:100%;margin:4px 0 13px;padding:8px;border:1.5px solid #d1d5db;border-radius:7px;font-size:13px;background:#fff';
    ovl.innerHTML=
      '<div style="background:#fff;border-radius:12px;padding:22px 26px;width:440px;max-width:92vw;box-shadow:0 10px 40px rgba(0,0,0,.25)">'
      +'<h3 style="margin:0 0 4px;font-size:17px">📝 Στοιχεία περιγραφής</h3>'
      +'<div style="font-size:12.5px;color:#6b7280;margin-bottom:14px">'+model.seriesLabel+(ctx.pumpKw?' • '+ctx.pumpKw:'')+' — ό,τι μείνει κενό απλώς δεν θα αναφερθεί στο έγγραφο.</div>'
      +'<label style="font-weight:700;font-size:13px">Θέση τοποθέτησης εξωτερικής μονάδας</label>'
      +'<select id="pg-place" style="'+selStyle+'">'
      +'<option value="">— χωρίς αναφορά —</option>'
      +'<option>στο μπαλκόνι της κατοικίας</option>'
      +'<option>στην ταράτσα της κατοικίας</option>'
      +'<option>στην αυλή της κατοικίας</option>'
      +'<option>στον ακάλυπτο χώρο της οικοδομής</option>'
      +'</select>'
      +'<label style="font-weight:700;font-size:13px">Σύστημα διανομής θέρμανσης</label>'
      +'<select id="pg-dist" style="'+selStyle+'">'
      +'<option value="">— χωρίς αναφορά —</option>'
      +'<option>ενδοδαπέδια θέρμανση</option>'
      +'<option>θερμαντικά σώματα (καλοριφέρ)</option>'
      +'<option>fan coils</option>'
      +'</select>'
      +'<label style="display:flex;gap:8px;align-items:center;font-size:13.5px;margin:2px 0"><input type="checkbox" id="pg-rmboiler"> Αποσύνδεση υφιστάμενου λέβητα</label>'
      +'<label style="display:flex;gap:8px;align-items:center;font-size:13.5px;margin:6px 0 18px"><input type="checkbox" id="pg-rmtank"> Αποσύνδεση δεξαμενής πετρελαίου</label>'
      +'<div style="display:flex;gap:10px;justify-content:flex-end">'
      +'<button id="pg-cancel" style="border-radius:7px;padding:8px 18px;font-size:13px;font-weight:600;cursor:pointer;border:1.5px solid #d1d5db;background:#fff;color:#374151">Άκυρο</button>'
      +'<button id="pg-go" style="border-radius:7px;padding:8px 18px;font-size:13px;font-weight:600;cursor:pointer;border:1.5px solid #7c3aed;background:#7c3aed;color:#fff">Δημιουργία Word</button>'
      +'</div></div>';
    document.body.appendChild(ovl);
    document.getElementById('pg-cancel').onclick=function(){ovl.remove();};
    document.getElementById('pg-go').onclick=function(){
      var opts={
        place:document.getElementById('pg-place').value,
        dist:document.getElementById('pg-dist').value,
        rmBoiler:document.getElementById('pg-rmboiler').checked,
        rmTank:document.getElementById('pg-rmtank').checked
      };
      ovl.remove();
      buildDoc(ctx,model,opts).catch(function(e){alert('Σφάλμα δημιουργίας εγγράφου: '+(e&&e.message?e.message:e));});
    };
  }

  // ---------- Σύνταξη του εγγράφου Word ----------
  async function buildDoc(ctx,model,opts){
    var D=docx,P=D.Paragraph,T=D.TextRun,H=D.HeadingLevel,A=D.AlignmentType,IR=D.ImageRun;
    var FLOAT_OK=!!(D.TextWrappingType&&D.TextWrappingSide&&D.HorizontalPositionRelativeFrom&&D.VerticalPositionRelativeFrom&&D.HorizontalPositionAlign);
    function floatImg(b64,w,h){
      return new IR({data:b64u8(b64),transformation:{width:w,height:h},
        floating:{
          horizontalPosition:{relative:D.HorizontalPositionRelativeFrom.MARGIN,align:D.HorizontalPositionAlign.RIGHT},
          verticalPosition:{relative:D.VerticalPositionRelativeFrom.PARAGRAPH,offset:0},
          wrap:{type:D.TextWrappingType.SQUARE,side:D.TextWrappingSide.LEFT},
          margins:{left:114300,bottom:91440}
        }});
    }
    function inlineImg(b64,w,h){
      return new P({children:[new IR({data:b64u8(b64),transformation:{width:w,height:h}})],alignment:A.CENTER,spacing:{before:60,after:120}});
    }
    var bd={style:D.BorderStyle.SINGLE,size:1,color:'C9CED6'};
    var borders={top:bd,bottom:bd,left:bd,right:bd};
    function cellP(txt,o){o=o||{};return new P({children:[new T({text:txt,bold:!!o.b,size:o.s||22,color:o.c||'111827'})],alignment:o.right?A.RIGHT:A.LEFT,spacing:{after:0}});}
    function tc(p,w,fill,span){var c={children:[p],borders:borders,margins:{top:70,bottom:70,left:120,right:120}};if(w)c.width={size:w,type:D.WidthType.DXA};if(fill)c.shading={fill:fill,type:D.ShadingType.CLEAR};if(span)c.columnSpan=span;return new D.TableCell(c);}
    // Κουτί στοιχείων: τίτλος (1 κελί σε 2 στήλες) + γραμμές «ετικέτα | τιμή»
    function infoBox(title,rows){
      var BW=[3200,5826];
      var trs=[new D.TableRow({children:[tc(cellP(title,{b:true}),null,'DBEAFE',2)]})];
      rows.forEach(function(r){
        trs.push(new D.TableRow({children:[tc(cellP(r[0],{b:true}),BW[0],'F8FAFC'),tc(cellP(r[1]),BW[1])]}));
      });
      return new D.Table({width:{size:9026,type:D.WidthType.DXA},columnWidths:BW,rows:trs});
    }
    var spacer=function(after){return new P({text:'',spacing:{after:after||120}});};

    var ch=[];

    // Επικεφαλίδα επιστολής
    ch.push(new P({children:[new T({text:'Βέροια '+ctx.todayStr})],spacing:{after:160}}));
    if(ctx.custName){ch.push(new P({children:[new T({text:'Προς: ',bold:true}),new T({text:ctx.custName})],spacing:{after:40}}));}
    ch.push(new P({children:[new T({text:'Θέμα: ',bold:true}),new T({text:'Τοποθέτηση Αντλίας Θερμότητας',bold:true})],spacing:{after:200}}));

    // Εισαγωγή εταιρείας
    ch.push(new P({text:'Σας ευχαριστούμε για το ενδιαφέρον και την εμπιστοσύνη σας να προμηθευτείτε προϊόντα και υπηρεσίες από την εταιρεία μας.',spacing:{after:100}}));
    ch.push(new P({text:'Όλα τα προϊόντα είναι επώνυμα και πιστοποιημένης απόδοσης και ποιότητας. Η εταιρεία ΑΦΟΙ Χουρσουλίδη Κατασκευαστική Ο.Ε. διασφαλίζει τη σωστή τοποθέτηση, την καλή λειτουργία της τελικής εγκατάστασης και την περαιτέρω τεχνική υποστήριξη του συστήματος με συνεργεία από έμπειρους τεχνικούς.',spacing:{after:100}}));
    ch.push(new P({text:'Στην παρακάτω οικονομική προσφορά θα βρείτε δύο προτεινόμενες λύσεις για αντλία θερμότητας.',spacing:{after:200}}));

    // Τρία κουτιά στοιχείων κτιρίου
    var bx=buildingRows(ctx);
    if(bx.box1.length){ch.push(infoBox('Ταυτότητα κτιρίου',bx.box1));ch.push(spacer(120));}
    if(bx.box2.length){ch.push(infoBox('Δεδομένα υπολογισμού απωλειών του κτιρίου',bx.box2));ch.push(spacer(120));}
    if(bx.box3.length){ch.push(infoBox('Δομικά στοιχεία κτιρίου, σύμφωνα με δήλωση του πελάτη',bx.box3));ch.push(spacer(160));}

    // Πρόταση συστήματος — φωτογραφία (εγκατεστημένη) δίπλα στο κείμενο
    ch.push(new P({text:'Πρόταση: Αντλία θερμότητας '+model.seriesLabel+(ctx.pumpKw?' ('+ctx.pumpKw+')':''),heading:H.HEADING_1,spacing:{before:200,after:120}}));
    var techRuns=[];
    if(model.images&&model.images.amb&&FLOAT_OK)techRuns.push(floatImg(model.images.amb,250,178));
    techRuns.push(new T({text:model.tech(ctx)}));
    ch.push(new P({children:techRuns,spacing:{after:80}}));
    if(model.techCaption)ch.push(new P({children:[new T({text:model.techCaption,italics:true,size:16,color:'6B7280'})],spacing:{after:160}}));
    if(model.images&&model.images.amb&&!FLOAT_OK)ch.push(inlineImg(model.images.amb,400,285));

    // Κεντρικό σύστημα ελέγχου — εσωτερική μονάδα δίπλα στο κείμενο
    if(model.controller){
      ch.push(new P({text:'Κεντρικό σύστημα ελέγχου',heading:H.HEADING_2,spacing:{before:60,after:100}}));
      var ctrlRuns=[];
      if(model.images&&model.images.inner&&FLOAT_OK)ctrlRuns.push(floatImg(model.images.inner,190,135));
      ctrlRuns.push(new T({text:model.controller}));
      ch.push(new P({children:ctrlRuns,spacing:{after:160}}));
      if(model.images&&model.images.inner&&!FLOAT_OK)ch.push(inlineImg(model.images.inner,260,185));
    }

    // Συγκριτικά πλεονεκτήματα
    ch.push(new P({text:'Συγκριτικά πλεονεκτήματα του προτεινόμενου συστήματος',heading:H.HEADING_2,spacing:{before:60,after:100}}));
    model.advantages(ctx).forEach(function(t){ch.push(new P({text:t,spacing:{after:100}}));});

    // Ενότητες προσφοράς
    var pumpSec=null,bufSec=null,boilSec=null;
    ctx.secs.forEach(function(s){
      if(s.id==='pump')pumpSec=s;
      else if(s.id==='buffer')bufSec=s;
      else if(s.id==='boiler')boilSec=s;
    });

    // Δοχείο αδρανείας
    if(bufSec){
      ch.push(new P({text:'Δοχείο αδρανείας – Υδραυλικός διαχωριστής',heading:H.HEADING_2,spacing:{before:120,after:100}}));
      ch.push(new P({text:bufferText(bufSec),spacing:{after:120}}));
    }

    // Μπόιλερ ζεστού νερού
    if(boilSec){
      ch.push(new P({text:'Ζεστό νερό χρήσης',heading:H.HEADING_2,spacing:{before:120,after:100}}));
      ch.push(new P({text:boilerText(boilSec),spacing:{after:120}}));
    }

    // Υλικά μηχανοστασίου — μόνο τα βασικά (τα υπόλοιπα δεν εμφανίζονται)
    var mats=materialsList(pumpSec,bufSec,boilSec,opts);
    if(mats.length){
      ch.push(new P({text:'Υλικά μηχανοστασίου',heading:H.HEADING_2,spacing:{before:120,after:100}}));
      mats.forEach(function(m){ch.push(new P({text:m,bullet:{level:0},spacing:{after:50}}));});
    }

    // Εργασίες — εξωτερική μονάδα δίπλα στο κείμενο
    ch.push(new P({text:'Εργασίες',heading:H.HEADING_2,spacing:{before:160,after:100}}));
    var workRuns=[];
    if(model.images&&model.images.ext&&FLOAT_OK)workRuns.push(floatImg(model.images.ext,230,163));
    workRuns.push(new T({text:'Όλες οι εργασίες θα γίνουν από εξειδικευμένα συνεργεία με την κατάλληλη θεωρητική και πρακτική κατάρτιση. Θα υπάρξει πρόνοια για την κατά το δυνατόν μικρότερη ενόχληση των ενοίκων από τις εργασίες του συνεργείου μας και φυσικά σεβασμός των ωρών κοινής ησυχίας.'}));
    ch.push(new P({children:workRuns,spacing:{after:100}}));
    if(model.images&&model.images.ext&&!FLOAT_OK)ch.push(inlineImg(model.images.ext,320,228));
    ch.push(new P({text:'Αναλυτικότερα, οι εργασίες που θα γίνουν είναι:',spacing:{after:80}}));
    var works=[];
    if(opts.rmBoiler||opts.rmTank){
      var rp=[];if(opts.rmBoiler)rp.push('του υφιστάμενου λέβητα');if(opts.rmTank)rp.push('της δεξαμενής πετρελαίου');
      works.push('Αποσύνδεση '+rp.join(' και ')+' από την εγκατάσταση.');
    }
    works.push('Τοποθέτηση της εξωτερικής μονάδας της αντλίας θερμότητας'+(opts.place?' '+opts.place:'')+'.');
    if(bufSec)works.push('Τοποθέτηση και σύνδεση του δοχείου αδρανείας – υδραυλικού διαχωριστή.');
    if(boilSec)works.push('Τοποθέτηση και σύνδεση του μπόιλερ ζεστού νερού χρήσης.');
    if(opts.dist)works.push('Σύνδεση με το υφιστάμενο σύστημα διανομής ('+opts.dist+').');
    if(pumpSec&&pumpSec.items.some(function(i){return i.id==='ap';}))works.push('Τοποθέτηση του συστήματος πλήρωσης της εγκατάστασης.');
    works.push('Τοποθέτηση του χειριστηρίου – αισθητηρίου χώρου.');
    works.push('Θέση σε λειτουργία, δοκιμές και παράδοση με οδηγίες χρήσης.');
    works.forEach(function(w){ch.push(new P({text:w,bullet:{level:0},spacing:{after:50}}));});
    var totalDays=ctx.secs.reduce(function(a,s){return a+(s.laborDays||0);},0);
    if(totalDays>0){ch.push(new P({children:[new T({text:'Εκτιμώμενη διάρκεια εργασιών: ',bold:true}),new T({text:'περίπου '+totalDays+' εργάσιμες ημέρες.'})],spacing:{before:60,after:120}}));}

    // Πίνακας αξιών — 2 στήλες: καθαρές αξίες ευδιάκριτες, ΦΠΑ/τελικό μικρότερα
    ch.push(new P({text:'Η αξία της παραπάνω επένδυσης ανέρχεται στα:',heading:H.HEADING_2,spacing:{before:120,after:120}}));
    var CW2=[6726,2300];
    var rows=[];
    rows.push(new D.TableRow({children:[tc(cellP('Είδος',{b:true}),CW2[0],'EFF6FF'),tc(cellP('Αξία',{b:true,right:true}),CW2[1],'EFF6FF')]}));
    rows.push(new D.TableRow({children:[
      tc(cellP('Προμήθεια αντλίας θερμότητας '+model.seriesLabel.split(' ')[0]+' '+ctx.pumpName+(ctx.pumpKw?' ('+ctx.pumpKw+')':'')),CW2[0]),
      tc(cellP(fmtE(ctx.pumpRetail),{b:true,right:true}),CW2[1])
    ]}));
    ctx.secs.forEach(function(s){
      if(!s.retail||s.retail<=0)return;
      rows.push(new D.TableRow({children:[
        tc(cellP(s.label+' — υλικά & εργασία'),CW2[0]),
        tc(cellP(fmtE(s.retail),{b:true,right:true}),CW2[1])
      ]}));
    });
    rows.push(new D.TableRow({children:[
      tc(cellP('ΣΥΝΟΛΟ:',{b:true,s:24}),CW2[0],'F0FDF4'),
      tc(cellP(fmtE(ctx.totalNet),{b:true,right:true,s:26,c:'16A34A'}),CW2[1],'F0FDF4')
    ]}));
    rows.push(new D.TableRow({children:[
      tc(cellP('ΦΠΑ 24%:',{s:18,c:'6B7280'}),CW2[0]),
      tc(cellP(fmtE(ctx.vat),{right:true,s:18,c:'6B7280'}),CW2[1])
    ]}));
    rows.push(new D.TableRow({children:[
      tc(cellP('Σύνολο με ΦΠΑ:',{s:18,c:'6B7280'}),CW2[0]),
      tc(cellP(fmtE(ctx.totalWithVat),{right:true,s:18,c:'6B7280'}),CW2[1])
    ]}));
    ch.push(new D.Table({width:{size:9026,type:D.WidthType.DXA},columnWidths:CW2,rows:rows}));
    ch.push(spacer(160));

    // Σημειώσεις
    ch.push(new P({text:'Σημειώσεις',heading:H.HEADING_2,spacing:{before:60,after:100}}));
    ch.push(new P({text:'Θα πρέπει να γίνει έλεγχος της ηλεκτρικής παροχής και του πίνακα από ηλεκτρολόγο. Στην προσφορά μας δεν περιλαμβάνονται ηλεκτρολογικές εργασίες στον πίνακα της κατοικίας.',bullet:{level:0},spacing:{after:50}}));
    ch.push(new P({text:'Δεν περιλαμβάνεται γερανός για την ανύψωση της εξωτερικής μονάδας ή την απομάκρυνση παλαιού εξοπλισμού, εφόσον απαιτηθεί.',bullet:{level:0},spacing:{after:160}}));
    ch.push(new P({text:'Παραμένουμε στη διάθεσή σας για κάθε διευκρίνιση.',spacing:{after:200}}));

    // Εναλλακτική πρόταση — κενός σκελετός για χειροκίνητη συμπλήρωση
    ch.push(new P({text:'Εναλλακτικά με αντλία θερμότητας _________',heading:H.HEADING_2,spacing:{before:120,after:120}}));
    var CW4=[4226,1700,1500,1600];
    var altRows=[
      new D.TableRow({children:[
        tc(cellP('Είδος',{b:true}),CW4[0],'EFF6FF'),
        tc(cellP('Αξία',{b:true,right:true}),CW4[1],'EFF6FF'),
        tc(cellP('ΦΠΑ',{b:true,right:true}),CW4[2],'EFF6FF'),
        tc(cellP('Σύνολο',{b:true,right:true}),CW4[3],'EFF6FF')
      ]}),
      new D.TableRow({children:[
        tc(cellP('Προμήθεια & τοποθέτηση αντλίας θερμότητας _________________________ (___ kW):'),CW4[0]),
        tc(cellP('€',{right:true}),CW4[1]),
        tc(cellP('€',{right:true}),CW4[2]),
        tc(cellP('€',{right:true}),CW4[3])
      ]})
    ];
    ch.push(new D.Table({width:{size:9026,type:D.WidthType.DXA},columnWidths:CW4,rows:altRows}));
    ch.push(spacer(240));

    // Υπογραφή
    ch.push(new P({children:[new T({text:'ΑΦΟΙ Χουρσουλίδη Κατασκευαστική Ο.Ε.',bold:true})],alignment:A.RIGHT,spacing:{after:0}}));

    var doc=new D.Document({
      styles:{
        default:{document:{run:{font:'Calibri',size:22}}},
        paragraphStyles:[
          {id:'Heading1',name:'Heading 1',basedOn:'Normal',next:'Normal',quickFormat:true,run:{size:30,bold:true,color:'0F4C81',font:'Calibri'},paragraph:{spacing:{before:240,after:120},outlineLevel:0}},
          {id:'Heading2',name:'Heading 2',basedOn:'Normal',next:'Normal',quickFormat:true,run:{size:26,bold:true,color:'111827',font:'Calibri'},paragraph:{spacing:{before:180,after:100},outlineLevel:1}}
        ]
      },
      sections:[{properties:{},children:ch}]
    });
    var blob=await D.Packer.toBlob(doc);
    var url=URL.createObjectURL(blob);
    var a=document.createElement('a');
    a.href=url;
    a.download='Prosfora_'+(ctx.custName?ctx.custName.replace(/\s+/g,'_'):'Pelatis')+'_'+String(ctx.pumpName).replace(/\s+/g,'_')+'.docx';
    document.body.appendChild(a);a.click();document.body.removeChild(a);
    setTimeout(function(){URL.revokeObjectURL(url);},2000);
  }

  // ---------- Δημόσιο interface ----------
  return {
    version:2,
    start:function(ctx){
      if(typeof docx==='undefined'){alert('Δεν φορτώθηκε η βιβλιοθήκη Word. Ελέγξτε τη σύνδεση στο internet και δοκιμάστε ξανά.');return;}
      var model=null;
      for(var i=0;i<MODELS.length;i++){if(MODELS[i].match(ctx)){model=MODELS[i];break;}}
      if(!model){
        alert('Δεν υπάρχουν ακόμη κείμενα περιγραφής για αυτό το μοντέλο.\nΔιαθέσιμες σειρές: '+MODELS.map(function(m){return m.seriesLabel;}).join(', ')+'.');
        return;
      }
      showDialog(ctx,model);
    }
  };
})();